sys_ux_client_script.script:
/**
 * @param {params} params
 * @param {api} params.api
 * @param {any} params.event
 * @param {any} params.imports
 * @param {ApiHelpers} params.helpers
 */
function handler({ api, event, helpers, imports }) {

    var nf = imports['x_snc_nf.NextFormUtil']();
    api.emit('CTRL_NEXTFORM#FIELD_VALUE_CHANGED');

    const fieldName = event.payload.fieldName;
    var prev = api.state.fields[fieldName];
    if (!prev) {
        return;
    }

    var updatedField = Object.assign({}, prev, {
        value: event.payload.value,
        displayValue: event.payload.displayValue
    });
    const newFields = Object.assign({}, api.state.fields);
    newFields[fieldName] = updatedField;
    api.setState('fields', newFields);
    const vr = nf.validateField(updatedField);
    const onLast = api.state.currentScreenNumber === api.state.screenCount;
    api.setState('canProcess', onLast && !api.state.isProcessed && vr);
}
